20	/** @file*/
21	
22	#include "internal_nn_math.h"
23	#include "riscv_nn_support.h"
24	
25	//// Convolution Functions
26	int32_t riscv_nn_conv_HWC_s8_s8_s8_sft_bias(const q7_t * in_tensor,
27	                       const uint16_t in_tensor_dim,
28	                       const uint16_t in_tensor_ch,
29	                       const q7_t * ker_weight,
30	                       const uint16_t out_tensor_ch,
31	                       const uint16_t ker_dim,
32	                       const uint16_t pad,
33	                       const uint16_t stride,
34	                       const q7_t * bias,
35	                       const uint16_t bias_lshift,
36	                       const uint16_t out_rshift,
37	                       q7_t * out_tensor,
38	                       const uint16_t out_tensor_dim,
39	                       q15_t * in_tmp_buf,
40	                       q7_t * tmp_buf)
41	{
42	#ifdef ENA_EMPTY_FUN
43	    //empty body
44	#elif defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)
45	    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
46	
47	    /*
48	     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
49	     *  im2col are done to output in q15_t format from q7_t input
50	     */
51	    q7_t    *pBuffer = (q7_t*)in_tmp_buf;
52	    q7_t    *pOut = out_tensor;
53	
54	    /* This part implements the im2col function */
55	    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
56	    {
57	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
58	        {
59	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
60	            {
61	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
62	                {
63	                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
64	                    {
65	                        /* Filling 0 for out-of-bound paddings */
66	                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
67	                    }
68	                    else
69	                    {
70	                        /* Copying the pixel data to column */
71	                        nn_dup_s8((q7_t *)in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
72	                    }
73	                    pBuffer += in_tensor_ch;
74	                }
75	            }
76	
77	            /* Computation is filed for every 2 columns */
78	            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
79	            {
80	                pOut = nn_mat_mul_kernel_q7(ker_weight,
81	                                            (q7_t*)in_tmp_buf,
82	                                            out_tensor_ch,
83	                                            in_tensor_ch * ker_dim * ker_dim,
84	                                            bias_lshift,
85	                                            out_rshift,
86	                                            bias,
87	                                            pOut);
88	
89	                /* counter reset */
90	                pBuffer = (q7_t*)in_tmp_buf;
91	            }
92	        }
93	    }
94	
95	    /* check if there is left-over for compute */
96	#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
97	    if (pBuffer != (q7_t *)in_tmp_buf)
98	    {
99	        unsigned vl;
100	        const q7_t *p_wt = ker_weight;
101	        int       i;
102	        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
103	        long vlenb = NDS_VEC_CSR_GET_VLENB();
104	
105	        vl = __riscv_vsetvl_e32m1(1);
106	        vint32m1_t  vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0, vl);   //const zero for redsum
107	
108	        for (i = 0; i < out_tensor_ch; i++)
109	        {
110	            q7_t      *p_in = (q7_t*)in_tmp_buf;
111	            uint16_t colCnt2 = colCnt;
112	
113	            //clear v0~v7
114	            vl = __riscv_vsetvl_e32m8(colCnt);
115	            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
116	
117	            while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
118	            {
119	                vl = __riscv_vsetvl_e8m8(colCnt2);
120	                //load src1
121	                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
122	                //load src2
123	                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
124	                //bump pointers and update loop counter
125	                colCnt2 -= vl;
126	                p_wt += vl;
127	                p_in += vl;
128	                //set the proper avl/SEW/LMUL values for vd4dot
129	                vl >>= 2;
130	                vl = __riscv_vsetvl_e32m8(vl);
131	                //acc += src1 * src2
132	                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
133	
134	            }
135	
136	            //extra process for the case of vd4dot's avl is not a mutiple of 4
137	            if(colCnt2 > 0)
138	            {
139	                //clean one of the dot product source
140	                vl = __riscv_vsetvlmax_e8m8();
141	                vint8m8_t vP_wt_i8m8 = __riscv_vand(__riscv_vundefined_i8m8(), 0, vl);
142	
143	                vl = __riscv_vsetvl_e8m8(colCnt2);
144	                //load src1
145	                vP_wt_i8m8 = __riscv_vle8_v_i8m8_tu(vP_wt_i8m8, p_wt, vl);
146	                //load src2
147	                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
148	                //bump pointers and update loop counter
149	                colCnt2 -= vl;
150	                p_wt += vl;
151	                p_in += vl;
152	                //set the proper avl/SEW/LMUL values for vd4dot
153	                //remember to deal with the avl of vd4dot is not a multiple of 4 case
154	                vl = __riscv_vsetvl_e32m8(vl);
155	                //acc += src1 * src2
156	                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
157	            }
158	
159	            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
160	            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
161	
162	            //add bias back
163	            vl = __riscv_vsetvl_e32m1(1);
164	            vint8mf4_t vBias = __riscv_vle8_v_i8mf4(bias, vl);
165	            vint32m1_t vBias_i32m1  = __riscv_vsext_vf4(vBias, vl);
166	            vBias_i32m1 = __riscv_vsll(vBias_i32m1, bias_lshift, vl);
167	            vBias_i32m1 = __riscv_vadd(vBias_i32m1, NN_ROUND(out_rshift), vl);
168	            vSum = __riscv_vadd(vSum, vBias_i32m1, vl);
169	
170	            //scale down, clip and store the results
171	            vl = __riscv_vsetvl_e16mf2(1);
172	            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, out_rshift, vl);
173	            vl = __riscv_vsetvl_e8mf4(1);
174	            vint8mf4_t vSum_i8mf4 = __riscv_vnclip(vSum_i16mf2, 0, __RISCV_VXRM_RNU, vl);
175	            __riscv_vse8(pOut, vSum_i8mf4, vl);
176	
177	            bias += vl;
178	            pOut += vl;
179	        }
180	    }
181	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
182	    if (pBuffer != (q7_t *)in_tmp_buf)
183	    {
184	        unsigned vl;
185	        const q7_t *p_wt = ker_weight;
186	        int       i;
187	        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
188	        long vlenb = NDS_VEC_CSR_GET_VLENB();
189	
190	#if (__clang__)
191	        register const long zero asm ("x0") = 0;
192	#else
193	        register const long zero asm ("x0");
194	#endif
195	
196	        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
197	        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
198	
199	        for (i = 0; i < out_tensor_ch; i++)
200	        {
201	            q7_t      *p_in = (q7_t*)in_tmp_buf;
202	            uint16_t colCnt2 = colCnt;
203	
204	            //clear v0~v7
205	            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
206	            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
207	
208	            while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
209	            {
210	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
211	                //load src1
212	                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
213	                //load src2
214	                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
215	                //bump pointers and update loop counter
216	                colCnt2 -= vl;
217	                p_wt += vl;
218	                p_in += vl;
219	                //set the proper avl/SEW/LMUL values for vd4dot
220	                vl >>= 2;
221	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
222	                //acc += src1 * src2
223	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
224	            }
225	
226	            //extra process for the case of vd4dot's avl is not a mutiple of 4
227	            if(colCnt2 > 0)
228	            {
229	                //clean one of the dot product source
230	                NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
231	                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
232	
233	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
234	                //load src1
235	                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
236	                //load src2
237	                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
238	                //bump pointers and update loop counter
239	                colCnt2 -= vl;
240	                p_wt += vl;
241	                p_in += vl;
242	                //set the proper avl/SEW/LMUL values for vd4dot
243	                //remember to deal with the avl of vd4dot is not a multiple of 4 case
244	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
245	                //acc += src1 * src2
246	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
247	            }
248	
249	            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
250	            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);
251	
252	            //add bias back
253	            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
254	            NDS_VEC_VLB_V(NDS_VEC_V10, bias);
255	            NDS_VEC_VSEXT_VF4(NDS_VEC_V9, NDS_VEC_V10);
256	            NDS_VEC_VSLL_VX(NDS_VEC_V9, NDS_VEC_V9, bias_lshift);
257	            NDS_VEC_VADD_VX(NDS_VEC_V9, NDS_VEC_V9, NN_ROUND(out_rshift));
258	            NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V9);
259	
260	            //scale down, clip and store the results
261	            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
262	            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
263	            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
264	            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
265	            NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
266	
267	            bias += vl;
268	            pOut += vl;
269	        }
270	    }
271	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
272	    if (pBuffer != (q7_t *)in_tmp_buf)
273	    {
274	        unsigned vl;
275	        const q7_t *pA = ker_weight;
276	        int       i;
277	        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
278	
279	        //set SEW for 1st time VMV_S_X
280	        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
281	        vl = __riscv_vsetvl_e32m8(colCnt);
282	
283	        for (i = 0; i < out_tensor_ch; i++)
284	        {
285	            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
286	            q7_t      *pB = (q7_t*)in_tmp_buf;
287	            uint16_t colCnt2 = colCnt;
288	
289	            //init
290	            vint32m1_t vBias = __riscv_vmv_s_x_i32m1(sum, vl);
291	            //clear v8~v15
292	            vint32m8_t vAcc = __riscv_vundefined_i32m8();
293	            vAcc = __riscv_vand_tu(vAcc, vAcc, 0, vl);
294	
295	            while (colCnt2 > 0)
296	            {
297	                vl = __riscv_vsetvl_e8m2(colCnt2);
298	                vint8m2_t vPa_i8 = __riscv_vundefined_i8m2();
299	                vint8m2_t vPb_i8 = __riscv_vundefined_i8m2();
300	                //load src1
301	                vPa_i8 = __riscv_vle8_tu(vPa_i8, pA, vl);
302	                //load src2
303	                vPb_i8 = __riscv_vle8_tu(vPb_i8, pB, vl);
304	                //acc += src1 * src2
305	                vAcc = __riscv_vqmacc_vv_i32m8_tu(vAcc, vPa_i8, vPb_i8, vl);
306	                //bump pointers and update loop counter
307	                colCnt2 -= vl;
308	                pA += vl;
309	                pB += vl;
310	            }
311	
312	            vl = __riscv_vsetvl_e32m8(colCnt);    //note the avl here
313	            vint32m1_t vAcc_sum = __riscv_vredsum(vAcc, vBias, vl);
314	            //move vr results to gpr
315	            sum = __riscv_vmv_x(vAcc_sum);
316	
317	            *pOut++ = NDS_ISA_SATS((sum >> out_rshift), 8);
318	        }
319	    }
320	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
321	    if (pBuffer != (q7_t *)in_tmp_buf)
322	    {
323	        unsigned vl;
324	        const q7_t *pA = ker_weight;
325	        int       i;
326	        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
327	
328	        //set SEW for 1st time VMV_S_X
329	        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
330	        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
331	
332	        for (i = 0; i < out_tensor_ch; i++)
333	        {
334	            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
335	            q7_t      *pB = (q7_t*)in_tmp_buf;
336	            uint16_t colCnt2 = colCnt;
337	
338	            //init
339	            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
340	            //clear v8~v15
341	            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
342	
343	            while (colCnt2 > 0)
344	            {
345	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
346	                //load src1
347	                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
348	                //load src2
349	                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
350	                //acc += src1 * src2
351	                NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V4, NDS_VEC_V2);
352	                //bump pointers and update loop counter
353	                colCnt2 -= vl;
354	                pA += vl;
355	                pB += vl;
356	            }
357	
358	            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
359	            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V0);
360	            //move vr results to gpr
361	            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
362	
363	            *pOut++ = NDS_ISA_SATS((sum >> out_rshift), 8);
364	        }
365	    }
366	#elif defined(ENA_DSP_ISA_64)
367	    if (pBuffer != (q7_t*)in_tmp_buf)
368	    {
369	        const q7_t *pA = ker_weight;
370	        int i;
371	
372	        for (i = 0; i < out_tensor_ch; i++)
373	        {
374	            q63_t sum = 0;
375	            q7_t *pB = (q7_t*)in_tmp_buf;
376	            /* each time it process 8 entries */
377	            uint16_t  colCnt = (in_tensor_ch * ker_dim * ker_dim) >> 3;
378	
379	            while (colCnt)
380	            {
381	                long inA1, inB1;
382	
383	                inA1 = *__SIMD64(pA)++;
384	                inB1 = *__SIMD64(pB)++;
385	                sum  = NDS_DSP_SMAQA(sum, inA1, inB1);
386	                colCnt--;
387	            }
388	            //sum up the high and low part results (SIMD results)
389	            sum  = (q31_t)(sum >> 32) + (q31_t)sum;
390	
391	            colCnt = (in_tensor_ch * ker_dim * ker_dim) & 0x7;
392	            while (colCnt)
393	            {
394	                q7_t    inA1 = *pA++;
395	                q7_t    inB1 = *pB++;
396	                sum += inA1 * inB1;
397	                colCnt--;
398	            }
399	
400	            /* add bias back in to sum */
401	            sum += ((q31_t)(bias[i]) << bias_lshift) + NN_ROUND(out_rshift);
402	
403	            *pOut = NDS_DSP_SATS(((q31_t)sum >> out_rshift), 8);
404	            pOut++;
405	        }
406	    }
407	#else
408	    if (pBuffer != (q7_t*)in_tmp_buf)
409	    {
410	        const q7_t *pA = ker_weight;
411	        int i;
412	
413	        for (i = 0; i < out_tensor_ch; i++)
414	        {
415	            q31_t sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
416	            q7_t *pB = (q7_t*)in_tmp_buf;
417	            /* each time it process 4 entries */
418	            uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;
419	
420	            while (colCnt)
421	            {
422	                long inA1, inB1;
423	
424	                inA1 = *__SIMD32(pA)++;
425	                inB1 = *__SIMD32(pB)++;
426	                sum  = NDS_DSP_SMAQA(sum, inA1, inB1);
427	                colCnt--;
428	            }
429	
430	            colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
431	            while (colCnt)
432	            {
433	                q7_t    inA1 = *pA++;
434	                q7_t    inB1 = *pB++;
435	                sum += inA1 * inB1;
436	                colCnt--;
437	            }
438	
439	            *pOut = NDS_DSP_SATS((sum >> out_rshift), 8);
440	            pOut++;
441	        }
442	    }
443	#endif
444	#elif defined(ENA_DSP_ISA)
445	    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
446	
447	    /*
448	     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
449	     *  im2col are done to output in q15_t format from q7_t input
450	     */
451	    q15_t    *pBuffer = in_tmp_buf;
452	    q7_t     *pOut = out_tensor;
453	
454	    /* This part implements the im2col function */
455	    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
456	    {
457	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
458	        {
459	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
460	            {
461	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
462	                {
463	                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
464	                    {
465	                        /* Filling 0 for out-of-bound paddings */
466	                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
467	                    }
468	                    else
469	                    {
470	                        /* Copying the pixel data to column */
471	                        nn_dup_s8_s16((q7_t *)in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
472	                    }
473	                    pBuffer += in_tensor_ch;
474	                }
475	            }
476	
477	            /* Computation is filed for every 2 columns */
478	            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
479	            {
480	                pOut =
481	                    nn_mat_mul_kernel_q7_q15(ker_weight, in_tmp_buf,
482	                                             out_tensor_ch,
483	                                             in_tensor_ch *
484	                                             ker_dim * ker_dim, bias_lshift, out_rshift, bias, pOut);
485	
486	                /* counter reset */
487	                pBuffer = in_tmp_buf;
488	            }
489	        }
490	    }
491	
492	    /* left-over because odd number of output pixels */
493	    if (pBuffer != in_tmp_buf)
494	    {
495	        const q7_t *pA = ker_weight;
496	        int       i;
497	
498	        for (i = 0; i < out_tensor_ch; i++)
499	        {
500	            /* Load the accumulator with bias first */
501	            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
502	
503	            /* Point to the beging of the im2col buffer */
504	            q15_t    *pB = in_tmp_buf;
505	
506	            /* Each time it process 4 entries */
507	            uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;
508	
509	            while (colCnt)
510	            {
511	                q31_t     inA1, inA2;
512	                q31_t     inB1, inB2;
513	
514	                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
515	
516	                inB1 = *__SIMD32(pB)++;
517	                sum = NDS_DSP_KMADA(sum, inA1, inB1);
518	                inB2 = *__SIMD32(pB)++;
519	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
520	
521	                colCnt--;
522	            }
523	            colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
524	            while (colCnt)
525	            {
526	                q7_t      inA1 = *pA++;
527	                q15_t     inB1 = *pB++;
528	                sum += inA1 * inB1;
529	                colCnt--;
530	            }
531	            *pOut++ = (q7_t) NDS_DSP_SATS((sum >> out_rshift), 8);
532	        }
533	    }
534	#else
535	    uint16_t  i, j, k, l, m, n;
536	    int       conv_out;
537	    long in_row, in_col;
538	
539	    for (i = 0; i < out_tensor_ch; i++)
540	    {
541	        for (j = 0; j < out_tensor_dim; j++)
542	        {
543	            for (k = 0; k < out_tensor_dim; k++)
544	            {
545	                conv_out = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
546	                for (m = 0; m < ker_dim; m++)
547	                {
548	                    for (n = 0; n < ker_dim; n++)
549	                    {
550	                        // if-for implementation
551	                        in_row = stride * j + m - pad;
552	                        in_col = stride * k + n - pad;
553	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
554	                        {
555	                            for (l = 0; l < in_tensor_ch; l++)
556	                            {
557	                                conv_out +=
558	                                    in_tensor[(in_row * in_tensor_dim + in_col) * in_tensor_ch + l]
559	                                    * ker_weight[i * in_tensor_ch * ker_dim * ker_dim + (m * ker_dim + n) * in_tensor_ch + l];
560	                            }
561	                        }
562	                    }
563	                }
564	                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = (q7_t) NDS_ISA_SATS((conv_out >> out_rshift), 8);
565	            }
566	        }
567	    }
568	
569	#endif                          /* ENA_DSP_ISA */
570	
571	    return 0;
572	}
