39	    q7_t *pOut2 = out + out_tensor_ch;
40	    q7_t *pOut3 = out + out_tensor_ch * 2;
41	    q7_t *pOut4 = out + out_tensor_ch * 3;
42	
43	    const q7_t *pA = src1;
44	
45	#if (__clang__)
46	    register const long zero asm ("x0") = 0;
47	#else
48	    register const long zero asm ("x0");
49	#endif
50	    vl = __riscv_vsetvl_e32m1(1);
51	    vint32m1_t vZero = __riscv_vundefined_i32m1();
52	    vZero = __riscv_vand_tu(vZero, vZero, zero, vl);    //const zero for redsum
53	
54	    while(rowCnt > 0)
55	    {
56	        // setup pointers for A
57	        const q7_t *pA2 = pA + col_src1;
58	        const q7_t *pA3 = pA + col_src1 * 2;
59	        const q7_t *pA4 = pA + col_src1 * 3;
