61	        const q7_t *pB = src2;
62	        const q7_t *pB2 = pB + col_src1;
63	        const q7_t *pB3 = pB + col_src1 * 2;
64	        const q7_t *pB4 = pB + col_src1 * 3;
65	
66	        vl = __riscv_vsetvlmax_e32m1();
67	        vint32m1_t vAcc0 = __riscv_vundefined_i32m1();
68	        vint32m1_t vAcc1 = __riscv_vundefined_i32m1();
69	        vint32m1_t vAcc2 = __riscv_vundefined_i32m1();
70	        vint32m1_t vAcc3 = __riscv_vundefined_i32m1();
71	        vint32m1_t vAcc4 = __riscv_vundefined_i32m1();
72	        vint32m1_t vAcc5 = __riscv_vundefined_i32m1();
73	        vint32m1_t vAcc6 = __riscv_vundefined_i32m1();
74	        vint32m1_t vAcc7 = __riscv_vundefined_i32m1();
75	        vint32m1_t vAcc8 = __riscv_vundefined_i32m1();
76	        vint32m1_t vAcc9 = __riscv_vundefined_i32m1();
77	        vint32m1_t vAcc10 = __riscv_vundefined_i32m1();
78	        vint32m1_t vAcc11 = __riscv_vundefined_i32m1();
79	        vint32m1_t vAcc12 = __riscv_vundefined_i32m1();
80	        vint32m1_t vAcc13 = __riscv_vundefined_i32m1();
